patch:
diff --git a/llvm/lib/Transforms/Utils/SimplifyLibCalls.cpp b/llvm/lib/Transforms/Utils/SimplifyLibCalls.cpp
index 5900ea37431b2..17cfd40c5f4dd 100644
--- a/llvm/lib/Transforms/Utils/SimplifyLibCalls.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyLibCalls.cpp
@@ -2407,7 +2407,7 @@ Value *LibCallSimplifier::optimizePow(CallInst *Pow, IRBuilderBase &B) {
     return Base;

   // pow(x, 2.0) -> x * x
-  if (match(Expo, m_SpecificFP(2.0)))
+  if (match(Expo, m_SpecificFP(2.0)) && Pow->doesNotAccessMemory())
     return B.CreateFMul(Base, Base, "square");

   if (Value *Sqrt = replacePowWithSqrt(Pow, B))

tests.test_body:
declare float @powf(float, float)

define float @pow2_strict(float %x) {
  %r = call float @powf(float %x, float 2.000000e+00)
  ret float %r
}

; Function Attrs: nocallback nofree nosync nounwind speculatable willreturn memory(none)
declare <2 x double> @llvm.pow.v2f64(<2 x double>, <2 x double>) #0

define <2 x double> @test_simplify12v(<2 x double> %x) {
  %retval = call <2 x double> @llvm.pow.v2f64(<2 x double> %x, <2 x double> splat (double 1.000000e+00))
  ret <2 x double> %retval
}

attributes #0 = { nocallback nofree nosync nounwind speculatable willreturn memory(none) }

